mapper.select:
SELECT IF( COUNT(1), 'N', 'Y' ) AS checkYn
  FROM LETTNMENUINFO
 WHERE MENU_NO = #{menuNo}

mapper.insert:
INSERT INTO LETTNMENUINFO ( MENU_NM
                          , PROGRM_FILE_NM
                          , MENU_NO
                          , UPPER_MENU_NO
                          , MENU_ORDR
                          , MENU_DC
                          , RELATE_IMAGE_PATH
                          , RELATE_IMAGE_NM
                 ) VALUES ( #{menuNm}
                          , #{progrmFileNm}
                          , #{menuNo}
                          , #{upperMenuNo}
                          , #{menuOrdr}
                          , #{menuDc}
                          , #{relateImagePath}
                          , #{relateImageNm}
                          );

mapper.update:
UPDATE LETTNMENUINFO
   SET MENU_NM           = #{menuNm}
     , PROGRM_FILE_NM    = #{progrmFileNm}
     , MENU_NO           = #{menuNo}
     , UPPER_MENU_NO     = #{upperMenuNo}
     , MENU_ORDR         = #{menuOrdr}
     , MENU_DC           = #{menuDc}
     , RELATE_IMAGE_PATH = #{relateImagePath}
     , RELATE_IMAGE_NM   = #{relateImageNm}
 WHERE MENU_NO           = #{menuNo}
